-- Backfill: split qty/unit/prep out of legacy ingredient rows
-- ---------------------------------------------------------------------------
-- Fixes recipes imported before the parser fix: rows where the whole line was
-- stored in `name` with empty `unit` and NULL `quantity`
-- (e.g. name = "ВҪ teaspoon black pepper (for steak)").
--
-- Mirrors api/lib/import_extract.php :: parse_ingredient_line().
-- Tested on MariaDB 10.4; portable to MySQL 8.0+ (uses REGEXP_SUBSTR /
-- REGEXP_REPLACE with POSIX classes only, no replacement backreferences).
-- Idempotent: only touches rows still in the broken shape (quantity IS NULL
-- AND unit = '' AND the line starts with a number/fraction/known unit).
-- Re-running it changes nothing.
--
-- Quantities are written as DECIMAL: fractions become decimals (ВҪ -> 0.50,
-- "1 ВҪ" -> 1.50). Ranges ("1-2") and ascii fractions ("1/2") leave quantity
-- NULL but still split unit/name/prep. Free-text lines ("Salt to taste") and
-- already-parsed rows are left untouched.
--
-- HOW TO RUN (phpMyAdmin -> SQL tab), one step at a time:
--   STEP 1  run the backup
--   STEP 2  run the PREVIEW and eyeball new_* columns
--   STEP 3  run the UPDATE
--   ROLLBACK is at the bottom if anything looks wrong.
-- ===========================================================================

SET NAMES utf8mb4;

-- STEP 1 -- BACKUP (run once; rename the date if you re-run on another day) ---
CREATE TABLE IF NOT EXISTS ingredients_bak_20260612 AS SELECT * FROM ingredients;

-- STEP 2 -- PREVIEW (no writes). Review new_* before STEP 3. -----------------
SELECT id, raw_text,
  (CASE WHEN REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') REGEXP '^[0-9]+([.][0-9]+)?$' THEN CAST(REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') AS DECIMAL(10,2)) WHEN REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') REGEXP '^[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]$' THEN CASE REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') WHEN 'ВҪ' THEN 0.5 WHEN 'в…“' THEN 0.333 WHEN 'в…”' THEN 0.667 WHEN 'Вј' THEN 0.25 WHEN 'Вҫ' THEN 0.75 WHEN 'в…•' THEN 0.2 WHEN 'в…–' THEN 0.4 WHEN 'в…—' THEN 0.6 WHEN 'в…ҳ' THEN 0.8 WHEN 'в…ҷ' THEN 0.167 WHEN 'в…ҡ' THEN 0.833 WHEN 'в…ӣ' THEN 0.125 WHEN 'в…ң' THEN 0.375 WHEN 'в…қ' THEN 0.625 WHEN 'в…һ' THEN 0.875 WHEN 'в…җ' THEN 0.143 WHEN 'в…‘' THEN 0.111 WHEN 'в…’' THEN 0.1 ELSE NULL END WHEN REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') REGEXP '^[0-9]+[[:space:]]+[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]$' THEN CAST(REGEXP_SUBSTR(REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?'),'^[0-9]+') AS DECIMAL(10,2)) + CASE REGEXP_SUBSTR(REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?'),'[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]') WHEN 'ВҪ' THEN 0.5 WHEN 'в…“' THEN 0.333 WHEN 'в…”' THEN 0.667 WHEN 'Вј' THEN 0.25 WHEN 'Вҫ' THEN 0.75 WHEN 'в…•' THEN 0.2 WHEN 'в…–' THEN 0.4 WHEN 'в…—' THEN 0.6 WHEN 'в…ҳ' THEN 0.8 WHEN 'в…ҷ' THEN 0.167 WHEN 'в…ҡ' THEN 0.833 WHEN 'в…ӣ' THEN 0.125 WHEN 'в…ң' THEN 0.375 WHEN 'в…қ' THEN 0.625 WHEN 'в…һ' THEN 0.875 WHEN 'в…җ' THEN 0.143 WHEN 'в…‘' THEN 0.111 WHEN 'в…’' THEN 0.1 ELSE NULL END ELSE NULL END) AS new_quantity,
  (REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?','')),'^(?i)(?:teaspoons?|tsp|tablespoons?|tbsp|tbs|cups?|ounces?|oz|pounds?|lbs?|grams?|g|kilograms?|kg|milliliters?|millilitres?|ml|liters?|litres?|l|pinch(?:es)?|cloves?|cans?|packages?|pkgs?|sticks?|slices?|dash(?:es)?|quarts?|qt|pints?|pt|gallons?|gal|handfuls?|sprigs?|bunch(?:es)?)[.]?(?=[[:space:]]|$)')) AS new_unit,
  (TRIM(REGEXP_REPLACE(TRIM(REGEXP_REPLACE(TRIM(REGEXP_REPLACE(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?','')),'^(?i)(?:teaspoons?|tsp|tablespoons?|tbsp|tbs|cups?|ounces?|oz|pounds?|lbs?|grams?|g|kilograms?|kg|milliliters?|millilitres?|ml|liters?|litres?|l|pinch(?:es)?|cloves?|cans?|packages?|pkgs?|sticks?|slices?|dash(?:es)?|quarts?|qt|pints?|pt|gallons?|gal|handfuls?|sprigs?|bunch(?:es)?)[.]?(?=[[:space:]]|$)','')),'^(?i)of[[:space:]]+',''))) AS new_name,
  (TRIM(REGEXP_REPLACE(COALESCE(REGEXP_SUBSTR(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[(][^()]+[)][[:space:]]*$'),''),'[()]',''))) AS new_prep
FROM ingredients
WHERE quantity IS NULL AND unit = '' AND TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')) REGEXP '^([0-9]|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]|(?i)(?:teaspoons?|tsp|tablespoons?|tbsp|tbs|cups?|ounces?|oz|pounds?|lbs?|grams?|kilograms?|kg|milliliters?|millilitres?|ml|liters?|litres?|pinch(?:es)?|cloves?|cans?|packages?|pkgs?|sticks?|slices?|dash(?:es)?|quarts?|qt|pints?|pt|gallons?|gal|handfuls?|sprigs?|bunch(?:es)?)(?=[[:space:]]|$))'
ORDER BY recipe_id, position;

-- STEP 3 -- APPLY ----------------------------------------------------------
UPDATE ingredients SET
  prep_note = CASE WHEN (TRIM(REGEXP_REPLACE(COALESCE(REGEXP_SUBSTR(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[(][^()]+[)][[:space:]]*$'),''),'[()]',''))) <> '' THEN (TRIM(REGEXP_REPLACE(COALESCE(REGEXP_SUBSTR(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[(][^()]+[)][[:space:]]*$'),''),'[()]',''))) ELSE prep_note END,
  unit = (REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?','')),'^(?i)(?:teaspoons?|tsp|tablespoons?|tbsp|tbs|cups?|ounces?|oz|pounds?|lbs?|grams?|g|kilograms?|kg|milliliters?|millilitres?|ml|liters?|litres?|l|pinch(?:es)?|cloves?|cans?|packages?|pkgs?|sticks?|slices?|dash(?:es)?|quarts?|qt|pints?|pt|gallons?|gal|handfuls?|sprigs?|bunch(?:es)?)[.]?(?=[[:space:]]|$)')),
  quantity = (CASE WHEN REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') REGEXP '^[0-9]+([.][0-9]+)?$' THEN CAST(REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') AS DECIMAL(10,2)) WHEN REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])(?:[[:space:]]*(?:-|вҖ“|to)[[:space:]]*(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’])|[[:space:]]+(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]))?') REGEXP '^[ВҪв…“в…”ВјВҫв…•в…–в…—в…ҳв…ҷв…ҡв…җв…ӣв…ңв…қв…һв…‘в…’]$' THEN CASE REGEXP_SUBSTR(TRIM(REGEXP_REPLACE(REGEXP_REPLACE(name,'^[[:space:]]*[-*вҖўВ·][[:space:]]+',''),'[[:space:]]*[(][^()]*[)][[:space:]]*$','')),'^(?:[0-9]+(?:[.][0-9]+)?(?:[[:space:]]*/[[:space:]]*[0-9]+)?|[ВҪв…“в…”ВјВҫ